// // This module selects between two inputs, ALU_out and Shift_out, based on the control signal M4. If M4 is 1, the output MUX_4_out will be the value of ALU_out; if M4 is 0, the output will be the value of Shift_out.
module top_module(
    M4,
    ALU_out,
    Shift_out,
    MUX_4_out
    );parameter N=16;
input [N-1:0] ALU_out;
input [N-1:0] Shift_out;
input M4;
output reg [N-1:0] MUX_4_out;

always @ (*)

    begin 
    if (M4==0)
    MUX_4_out= ALU_out;

    else 
    MUX_4_out= Shift_out;
    end

endmodule
